"use client";

import {useState, useEffect, useRef} from "react";
import {Message} from "@/types/chat";
import {ChatMessage} from "@/components/ChatMessage";
import {ChatInput} from "@/components/ChatInput";
import {uploadImageToOss, streamChat} from "@/lib/api";
import {UtensilsCrossed} from "lucide-react";

export default function Home() {
    const [messages, setMessages] = useState<Message[]>([]);
    const [processing, setProcessing] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const messageIdCounter = useRef(0);

    // 滚动到底部
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({behavior: "smooth"});
    }, [messages]);

    // 添加消息
    const addMessage = (message: Omit<Message, "id" | "timestamp">) => {
        messageIdCounter.current += 1;
        const newMessage: Message = {
            ...message,
            id: `msg_${messageIdCounter.current}_${Date.now()}`,
            timestamp: Date.now(),
        };
        setMessages((prev) => [...prev, newMessage]);
        return newMessage;
    };

    // 处理发送消息
    const handleSend = async (text: string, file?: File) => {
        if (processing) return;

        let imageUrl: string | undefined;

        // 如果有图片，先上传到 OSS
        if (file) {
            try {
                imageUrl = await uploadImageToOss(file);
            } catch (error) {
                console.error("图片上传失败:", error);
                addMessage({
                    role: "assistant",
                    content: "图片上传失败，请稍后重试。",
                });
                return;
            }
        }

        // 添加用户消息
        addMessage({
            role: "user",
            content: text || "上传了一张食材图片",
            imageUrl,
        });

        setProcessing(true);

        // 添加助手消息（流式输出）
        const assistantMessageId = addMessage({
            role: "assistant",
            content: "",
            streaming: true,
        }).id;

        try {
            await streamChat(
                text || "这是我冰箱里的食物，帮我看看能做什么佳肴？",
                (chunk) => {
                    // 更新消息内容
                    setMessages((prev) =>
                        prev.map((msg) =>
                            msg.id === assistantMessageId
                                ? {...msg, content: msg.content + chunk}
                                : msg
                        )
                    );
                }, imageUrl,
                (error) => {
                    console.error("聊天失败:", error);
                    setMessages((prev) =>
                        prev.map((msg) =>
                            msg.id === assistantMessageId
                                ? {
                                    ...msg,
                                    content: msg.content + `\n[错误]: ${error.message}`,
                                    streaming: false,
                                }
                                : msg
                        )
                    );
                },
                () => {
                    // 流式输出完成
                    setMessages((prev) =>
                        prev.map((msg) =>
                            msg.id === assistantMessageId
                                ? {...msg, streaming: false}
                                : msg
                        )
                    );
                }
            );
        } finally {
            setProcessing(false);
        }
    };

    return (
        <div className="flex flex-col h-screen bg-gray-50">
            {/* 标题栏 */}
            <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center gap-3">
                <UtensilsCrossed className="text-orange-500" size={24}/>
                <div>
                    <h1 className="text-xl font-semibold">AI 私人厨师</h1>
                    <p className="text-sm text-gray-500">上传食材图片，获取个性化食谱推荐</p>
                </div>
            </header>

            {/* 聊天区域 */}
            <div className="flex-1 overflow-y-auto p-4">
                {messages.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-400">
                        <UtensilsCrossed size={64} className="mb-4 opacity-50"/>
                        <p className="text-lg">上传食材图片开始吧</p>
                        <p className="text-sm mt-2">我会帮您识别食材并推荐食谱</p>
                    </div>
                ) : (
                    <div className="max-w-3xl mx-auto">
                        {messages.map((message) => (
                            <ChatMessage key={message.id} message={message}/>
                        ))}
                        <div ref={messagesEndRef}/>
                    </div>
                )}
            </div>

            {/* 输入区域 */}
            <ChatInput onSend={handleSend} disabled={processing}/>
        </div>
    );
}